SELECT * FROM biz_visitor WHERE deleted = 0

    AND name LIKE CONCAT('%', #{params.name}, '%')


    AND phone LIKE CONCAT('%', #{params.phone}, '%')


    AND status = #{params.status}


    AND visit_date >= #{params.startDate}


    AND visit_date <= #{params.endDate}

ORDER BY create_time DESC

SELECT * FROM biz_visitor WHERE deleted = 0 AND status = #{status}

    AND name LIKE CONCAT('%', #{params.name}, '%')

ORDER BY create_time DESC
